import { useState, useRef, useEffect } from 'react'
import { Play, Pause, Volume2 } from 'lucide-react'
import { FadeIn } from '@/components/FadeIn'

export function SampleTab() {
  const audioRef = useRef<HTMLAudioElement>(null)
  const [isPlaying, setIsPlaying] = useState(false)
  const [progress, setProgress] = useState(0)
  const [duration, setDuration] = useState(0)
  const [currentTime, setCurrentTime] = useState(0)

  useEffect(() => {
    const audio = audioRef.current
    if (!audio) return
    const onTimeUpdate = () => {
      setCurrentTime(audio.currentTime)
      setProgress(audio.duration ? (audio.currentTime / audio.duration) * 100 : 0)
    }
    const onLoadedMetadata = () => setDuration(audio.duration)
    const onEnded = () => { setIsPlaying(false); setProgress(0); setCurrentTime(0) }
    audio.addEventListener('timeupdate', onTimeUpdate)
    audio.addEventListener('loadedmetadata', onLoadedMetadata)
    audio.addEventListener('ended', onEnded)
    return () => {
      audio.removeEventListener('timeupdate', onTimeUpdate)
      audio.removeEventListener('loadedmetadata', onLoadedMetadata)
      audio.removeEventListener('ended', onEnded)
    }
  }, [])

  const togglePlay = () => {
    const audio = audioRef.current
    if (!audio) return
    if (isPlaying) { audio.pause() } else { audio.play() }
    setIsPlaying(!isPlaying)
  }

  const handleSeek = (e: React.MouseEvent<HTMLDivElement>) => {
    const audio = audioRef.current
    if (!audio || !audio.duration) return
    const rect = e.currentTarget.getBoundingClientRect()
    audio.currentTime = ((e.clientX - rect.left) / rect.width) * audio.duration
  }

  const fmt = (t: number) => `${Math.floor(t / 60)}:${String(Math.floor(t % 60)).padStart(2, '0')}`

  return (
    <div className="pt-24 lg:pt-28">
      {/* ── Header ───────────────────────────────────── */}
      <section className="py-12 sm:py-16 lg:py-20">
        <div className="max-w-6xl mx-auto px-5 sm:px-8 lg:px-14">
          <FadeIn>
            <div className="text-center">
              <p className="text-primary-400 font-semibold text-sm mb-3">Sample</p>
              <h1 className="text-2xl sm:text-3xl lg:text-4xl font-bold text-ink">
                이런 노래가 만들어집니다
              </h1>
            </div>
          </FadeIn>
        </div>
      </section>

      {/* ── Sample Card ──────────────────────────────── */}
      <section className="pb-16 sm:pb-24 lg:pb-[100px]">
        <div className="max-w-6xl mx-auto px-5 sm:px-8 lg:px-14">
          <FadeIn>
            <div className="max-w-2xl mx-auto bg-white rounded-3xl overflow-hidden border border-neutral-200 shadow-sm">
              <audio ref={audioRef} src="/audio/식탁_위의_온기.mp3" preload="metadata" />

              {/* Album art area */}
              <div className="relative bg-gradient-to-br from-primary-100 to-primary-50 aspect-[16/9] flex items-center justify-center">
                <div className="absolute inset-0 flex items-center justify-center">
                  <button
                    onClick={togglePlay}
                    className="w-24 h-24 rounded-full bg-white/30 backdrop-blur-sm flex items-center justify-center hover:bg-white/50 transition-colors"
                  >
                    <div className="w-16 h-16 rounded-full bg-white/60 flex items-center justify-center">
                      {isPlaying
                        ? <Pause className="w-7 h-7 text-primary-400" fill="currentColor" />
                        : <Play className="w-7 h-7 text-primary-400 ml-1" fill="currentColor" />
                      }
                    </div>
                  </button>
                </div>
                <div className="absolute top-6 left-6 w-20 h-20 rounded-full bg-primary-200/40 blur-xl" />
                <div className="absolute bottom-8 right-8 w-32 h-32 rounded-full bg-primary-300/30 blur-2xl" />
              </div>

              {/* Song info */}
              <div className="p-6 sm:p-8">
                <div className="flex items-start gap-4">
                  <button
                    onClick={togglePlay}
                    className="flex-shrink-0 w-14 h-14 rounded-full bg-primary-400 flex items-center justify-center hover:bg-primary-500 transition-colors shadow-lg shadow-primary-200/50"
                  >
                    {isPlaying
                      ? <Pause className="w-6 h-6 text-white" fill="white" />
                      : <Play className="w-6 h-6 text-white ml-0.5" fill="white" />
                    }
                  </button>
                  <div>
                    <h3 className="text-xl font-bold text-ink">식탁 위의 온기</h3>
                    <p className="text-ink-muted text-sm mt-1">오리지널 — 엄마 칠순 선물</p>
                  </div>
                </div>

                {/* Waveform / progress */}
                <div
                  className="mt-6 h-10 bg-neutral-100 rounded-lg overflow-hidden cursor-pointer relative group"
                  onClick={handleSeek}
                >
                  <div className="absolute inset-0 flex items-end gap-[2px] px-1 py-1">
                    {Array.from({ length: 60 }, (_, i) => {
                      const h = 20 + Math.sin(i * 0.5) * 30 + Math.random() * 30
                      const filled = (i / 60) * 100 < progress
                      return (
                        <div
                          key={i}
                          className={`flex-1 rounded-full transition-colors ${filled ? 'bg-primary-400' : 'bg-primary-200'}`}
                          style={{ height: `${Math.min(h, 100)}%` }}
                        />
                      )
                    })}
                  </div>
                </div>
                <div className="flex justify-between mt-2 text-xs text-ink-faint">
                  <span>{fmt(currentTime)}</span>
                  <span>{duration ? fmt(duration) : '--:--'}</span>
                </div>

                <div className="mt-6 bg-neutral-50 rounded-xl p-5">
                  <p className="text-ink-light text-[15px] leading-relaxed">
                    40대 아들이 엄마 칠순에 선물한 오리지널 노래. 매일 새벽 도시락 싸주시던 엄마에게 전하는 30년 치 감사.
                  </p>
                  <p className="mt-4 text-ink-muted text-sm italic border-l-2 border-primary-300 pl-4">
                    "칠순잔치에서 틀어드렸는데 온 가족이 울었어요."
                  </p>
                </div>
              </div>
            </div>
          </FadeIn>
        </div>
      </section>

      {/* ── Before / After ───────────────────────────── */}
      <section className="py-16 sm:py-24 lg:py-[100px] bg-neutral-50">
        <div className="max-w-6xl mx-auto px-5 sm:px-8 lg:px-14">
          <FadeIn>
            <div className="text-center mb-12">
              <h2 className="text-2xl sm:text-3xl font-bold text-ink">
                같은 목소리인데, 노래가 되면 이렇게 다릅니다
              </h2>
            </div>
          </FadeIn>

          <FadeIn delay={0.15}>
            <div className="grid md:grid-cols-2 gap-6 max-w-3xl mx-auto">
              {/* Before */}
              <div className="rounded-2xl border border-neutral-200 bg-white p-6 sm:p-8">
                <div className="flex items-center gap-3 mb-5">
                  <div className="w-10 h-10 rounded-xl bg-neutral-100 flex items-center justify-center">
                    <Volume2 className="w-5 h-5 text-ink-muted" />
                  </div>
                  <div>
                    <p className="font-semibold text-ink text-sm">Before</p>
                    <p className="text-xs text-ink-muted">원본 음성 파일</p>
                  </div>
                </div>
                <div className="flex items-center gap-[2px] h-12 w-full">
                  {Array.from({ length: 40 }, (_, i) => {
                    const h = 15 + Math.random() * 70
                    return (
                      <div
                        key={i}
                        className="flex-1 rounded-full bg-neutral-300"
                        style={{ height: `${h}%` }}
                      />
                    )
                  })}
                </div>
                <div className="mt-3 flex items-center gap-3">
                  <button className="w-9 h-9 rounded-full bg-neutral-300 flex items-center justify-center hover:bg-neutral-400 transition-colors">
                    <Play className="w-4 h-4 text-white ml-0.5" fill="white" />
                  </button>
                  <p className="text-xs text-ink-muted">일상 대화 녹음</p>
                </div>
              </div>

              {/* After */}
              <div className="rounded-2xl border border-primary-200 bg-primary-50 p-6 sm:p-8">
                <div className="flex items-center gap-3 mb-5">
                  <div className="w-10 h-10 rounded-xl bg-primary-100 flex items-center justify-center">
                    <Volume2 className="w-5 h-5 text-primary-500" />
                  </div>
                  <div>
                    <p className="font-semibold text-ink text-sm">After</p>
                    <p className="text-xs text-ink-muted">완성된 노래</p>
                  </div>
                </div>
                <div className="flex items-center gap-[2px] h-12 w-full">
                  {Array.from({ length: 40 }, (_, i) => {
                    const h = 30 + Math.sin(i * 0.3) * 35 + 20
                    return (
                      <div
                        key={i}
                        className="flex-1 rounded-full bg-primary-300"
                        style={{ height: `${Math.min(h, 100)}%` }}
                      />
                    )
                  })}
                </div>
                <div className="mt-3 flex items-center gap-3">
                  <button className="w-9 h-9 rounded-full bg-primary-400 flex items-center justify-center hover:bg-primary-500 transition-colors shadow-md shadow-primary-200/40">
                    <Play className="w-4 h-4 text-white ml-0.5" fill="white" />
                  </button>
                  <p className="text-xs text-ink-muted">식탁 위의 온기</p>
                </div>
              </div>
            </div>
          </FadeIn>
        </div>
      </section>
    </div>
  )
}
